class Panel extends React.Component {
  constructor(props) {
    super(props);
    this.state = { isColor: props.isColor };
  }

  render() {
    return (
      <StyledPanel color={this.props.color}>{this.props.children}</StyledPanel>
    );
  }
}

export default Panel;

const StyledPanel = styled.div`
  user-select: none;
  cursor: default;
  margin: 3.5rem 1rem 3rem 1rem;
  padding: 5rem 3rem 3rem 3rem;
  background: ${(props) => props.color};
  display: flex;
  flex-direction: column;
  width: 70%;
  border-radius: 35px;
`;
